def bump_share_rule(model, j, h):
    return model.bh[j, h] <= 0.25 * sum(model.bh[jj, h] for jj in model.j)
model.bump_share = Constraint(model.j, model.h, rule=bump_share_rule)

def cap60_rule(model, i, j):
    if (i, j) not in model.ij:
        return Constraint.Skip
    return model.x[i, j] <= 0.6 * model.aa[i]
model.cap60 = Constraint(model.i, model.j, rule=cap60_rule)

def c_spread_rule(model, j):
    if ('c', j) not in model.ij:
        return Constraint.Skip
    return model.x['c', j] <= 0.5 * model.aa['c']
model.c_spread = Constraint(model.j, rule=c_spread_rule)

def r5_service_rule(model, h):
    if value(model.dd['route-5', h]) <= 0:
        return Constraint.Skip
    return model.bh['route-5', h] <= 0.6 * model.dd['route-5', h]
model.r5_service = Constraint(model.h, rule=r5_service_rule)
